// ── Validate required fields ──────────────────────────────
const body = $input.first().json.body || $input.first().json;
const required = ['name', 'email', 'subject', 'message'];
const missing = required.filter(f => !body[f] || String(body[f]).trim() === '');

if (missing.length > 0) {
  throw new Error(`Validation failed. Missing fields: ${missing.join(', ')}`);
}

// Basic email format check
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.email)) {
  throw new Error(`Invalid email format: ${body.email}`);
}

return [{ json: { ...body, validated: true } }];

// ── Generate unique ticket ID ─────────────────────────────
const now = new Date();
const datePart = now.toISOString().slice(0,10).replace(/-/g,'');
const randomPart = Math.floor(1000 + Math.random() * 9000);
const ticketId = `TKT-${datePart}-${randomPart}`;

const data = $input.first().json;
return [{
  json: {
    ticket_id:      ticketId,
    name:           data.name.trim(),
    email:          data.email.trim().toLowerCase(),
    subject:        data.subject.trim(),
    message:        data.message.trim(),
    source_channel: data.source_channel || 'webhook',
    received_at:    now.toISOString()
  }
}];

